const cors = require('cors');

// Allow all origins (dev only)
app.use(cors());

// Production: restrict origins
app.use(cors({
  origin: ['https://myapp.com'],
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  credentials: true
}));
```

Install with `npm install cors`. Never use open CORS in production.
